import React from 'react';
import './TopUsers.css';

const TopUsers = () => {
  const users = [
    { id: 1, name: 'darlingohioo', level: 9999, rank: 1 },
    { id: 2, name: 'mangalover', level: 8500, rank: 2 },
    { id: 3, name: 'animefan', level: 7200, rank: 3 },
  ];

  // Эмоджиларни аниклаш
  const getRankEmoji = (rank) => {
    if (rank === 1) return <span className="rank-emoji gold-crown">🥇</span>; // Олтин
    if (rank === 2) return <span className="rank-emoji silver-crown">🥈</span>; // Кумуш
    if (rank === 3) return <span className="rank-emoji bronze-crown">🥉</span>; // Бронза
    return rank; // 4-дан ошиклари учун рақам
  };

  return (
    <div className="top-users-card">
      <h3>
        <i className="fas fa-crown"></i>
        Топ пользователи
      </h3>
      <div className="users-grid">
        {users.map((user) => (
          <div 
            key={user.id} 
            className="user-card"
            data-rank={user.rank}
          >
            <div className="user-avatar">
              {getRankEmoji(user.rank)}
              <span className="user-rank">{user.rank}</span>
            </div>
            <div className="user-info">
              <div className="username">{user.name}</div>
              <div className="user-score">
                <i className="fas fa-star"></i>
                {user.level}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TopUsers;
